code = """import pandas as pd
import json
# Data from previous queries
rev = pd.DataFrame(var_call_Ymgf3dummIy4fZBNRmmz3FKr)
books = pd.DataFrame(var_call_T1PErDqhfnhNV2rJTmn8CiNO)
# Convert avg_rating and review_count to numeric
rev['avg_rating'] = pd.to_numeric(rev['avg_rating'], errors='coerce')
rev['review_count'] = pd.to_numeric(rev['review_count'], errors='coerce')
# Extract numeric id from purchase_id and create corresponding book_id
rev['id_num'] = rev['purchase_id'].str.extract(r'_(\d+)$')[0]
rev['book_id'] = 'bookid_' + rev['id_num']
# Merge with books on book_id
merged = pd.merge(books, rev, on='book_id', how='inner')
# Filter for avg_rating >= 4.5
filtered = merged[merged['avg_rating'] >= 4.5].copy()
# Select and format output
output = []
for _, row in filtered.iterrows():
    output.append({
        'book_id': row['book_id'],
        'title': row['title'],
        'avg_rating': float(row['avg_rating']),
        'review_count': int(row['review_count']),
        'categories': row['categories']
    })
# Sort by avg_rating desc then review_count desc
output = sorted(output, key=lambda x: (-x['avg_rating'], -x['review_count'], x['title']))
print("__RESULT__:")
print(json.dumps(output))"""

